package format

import (
	"bytes"
	"fmt"
	"sort"

	"github.com/hashicorp/terraform/internal/addrs"
	"github.com/hashicorp/terraform/internal/plans"
	"github.com/hashicorp/terraform/internal/schemarepo"
)

// CompactDiffFormatter formats a plan as a compact, summary-style diff showing
// only resource-level changes without attribute-level detail.
type CompactDiffFormatter struct{}

// Format renders a plan as a compact summary of resource changes.
// Changes are grouped by action type (Create, Update, Delete, Replace)
// and a summary count is shown at the end.
func (f *CompactDiffFormatter) Format(plan *plans.Plan, schemas *schemarepo.Schemas) string {
	if plan == nil || plan.Changes == nil {
		return ""
	}

	var buf bytes.Buffer

	// Group changes by action
	creates := []*plans.ResourceInstanceChangeSrc{}
	updates := []*plans.ResourceInstanceChangeSrc{}
	deletes := []*plans.ResourceInstanceChangeSrc{}
	replaces := []*plans.ResourceInstanceChangeSrc{}
	noop := []*plans.ResourceInstanceChangeSrc{}

	for _, change := range plan.Changes.Resources {
		// Skip deposed objects (only format the current object)
		if change.DeposedKey != "" {
			continue
		}

		switch change.Action {
		case plans.Create:
			creates = append(creates, change)
		case plans.Update:
			updates = append(updates, change)
		case plans.Delete:
			deletes = append(deletes, change)
		case plans.DeleteThenCreate, plans.CreateThenDelete:
			replaces = append(replaces, change)
		case plans.NoOp:
			noop = append(noop, change)
		default:
			// Handle other actions (Read, Forget, etc.)
			noop = append(noop, change)
		}
	}

	// Sort each group for consistent output
	sortChanges(creates)
	sortChanges(updates)
	sortChanges(deletes)
	sortChanges(replaces)

	// Output changes grouped by action type
	if len(creates) > 0 {
		buf.WriteString("# Create\n")
		for _, change := range creates {
			buf.WriteString(fmt.Sprintf("  [+] %s\n", change.Addr.String()))
		}
	}

	if len(updates) > 0 {
		buf.WriteString("# Update\n")
		for _, change := range updates {
			buf.WriteString(fmt.Sprintf("  [~] %s\n", change.Addr.String()))
		}
	}

	if len(replaces) > 0 {
		buf.WriteString("# Replace\n")
		for _, change := range replaces {
			buf.WriteString(fmt.Sprintf("  [-/+] %s\n", change.Addr.String()))
		}
	}

	if len(deletes) > 0 {
		buf.WriteString("# Delete\n")
		for _, change := range deletes {
			buf.WriteString(fmt.Sprintf("  [-] %s\n", change.Addr.String()))
		}
	}

	// Summary count
	total := len(creates) + len(updates) + len(replaces) + len(deletes)
	if total > 0 {
		buf.WriteString("\n")
		buf.WriteString(fmt.Sprintf("Plan: %d to add, %d to change, %d to destroy.\n",
			len(creates), len(updates)+len(replaces), len(deletes)))
	}

	return buf.String()
}

// sortChanges sorts changes by their address for consistent output
func sortChanges(changes []*plans.ResourceInstanceChangeSrc) {
	sort.Slice(changes, func(i, j int) bool {
		return changes[i].Addr.String() < changes[j].Addr.String()
	})
}

// FormatCompactDiff is a convenience function that creates a CompactDiffFormatter
// and formats the given plan.
func FormatCompactDiff(plan *plans.Plan, schemas *schemarepo.Schemas) string {
	formatter := &CompactDiffFormatter{}
	return formatter.Format(plan, schemas)
}

