func TestCompactDiffFormatterCreates(t *testing.T) {
	plan := &plans.Plan{
		Changes: &plans.ChangesSrc{
			Resources: []*plans.ResourceInstanceChangeSrc{
				{
					Addr: addrs.Resource{
						Mode: addrs.ManagedResourceMode,
						Type: "aws_instance",
						Name: "example",
					}.Instance(addrs.NoKey).Absolute(addrs.RootModuleInstance),
					ProviderAddr: addrs.AbsProviderConfig{
						Module:   addrs.RootModule,
						Provider: addrs.NewDefaultProvider("aws"),
					},
					ChangeSrc: plans.ChangeSrc{
						Action: plans.Create,
					},
				},
				{
					Addr: addrs.Resource{
						Mode: addrs.ManagedResourceMode,
						Type: "aws_subnet",
						Name: "example",
					}.Instance(addrs.NoKey).Absolute(addrs.RootModuleInstance),
					ProviderAddr: addrs.AbsProviderConfig{
						Module:   addrs.RootModule,
						Provider: addrs.NewDefaultProvider("aws"),
					},
					ChangeSrc: plans.ChangeSrc{
						Action: plans.Create,
					},
				},
			},
		},
	}

	formatter := &CompactDiffFormatter{}
	result := formatter.Format(plan, nil)

	if !strings.Contains(result, "# Create") {
		t.Fatalf("expected '# Create' in output, got: %s", result)
	}

	if !strings.Contains(result, "[+] aws_instance.example") {
		t.Fatalf("expected '[+] aws_instance.example' in output, got: %s", result)
	}

	if !strings.Contains(result, "[+] aws_subnet.example") {
		t.Fatalf("expected '[+] aws_subnet.example' in output, got: %s", result)
	}

	if !strings.Contains(result, "Plan: 2 to add, 0 to change, 0 to destroy") {
		t.Fatalf("expected summary count in output, got: %s", result)
	}
}

