func TestCompactDiffFormatterSorting(t *testing.T) {
	plan := &plans.Plan{
		Changes: &plans.ChangesSrc{
			Resources: []*plans.ResourceInstanceChangeSrc{
				{
					Addr: addrs.Resource{
						Mode: addrs.ManagedResourceMode,
						Type: "zebra_animal",
						Name: "example",
					}.Instance(addrs.NoKey).Absolute(addrs.RootModuleInstance),
					ProviderAddr: addrs.AbsProviderConfig{
						Module:   addrs.RootModule,
						Provider: addrs.NewDefaultProvider("zebra"),
					},
					ChangeSrc: plans.ChangeSrc{
						Action: plans.Create,
					},
				},
				{
					Addr: addrs.Resource{
						Mode: addrs.ManagedResourceMode,
						Type: "alpha_animal",
						Name: "example",
					}.Instance(addrs.NoKey).Absolute(addrs.RootModuleInstance),
					ProviderAddr: addrs.AbsProviderConfig{
						Module:   addrs.RootModule,
						Provider: addrs.NewDefaultProvider("alpha"),
					},
					ChangeSrc: plans.ChangeSrc{
						Action: plans.Create,
					},
				},
			},
		},
	}

	formatter := &CompactDiffFormatter{}
	result := formatter.Format(plan, nil)

	// Check that resources are sorted
	alphaIdx := strings.Index(result, "alpha_animal.example")
	zebraIdx := strings.Index(result, "zebra_animal.example")

	if alphaIdx == -1 || zebraIdx == -1 {
		t.Fatalf("missing expected resources in output: %s", result)
	}

	if alphaIdx > zebraIdx {
		t.Fatalf("resources not sorted correctly, got: %s", result)
	}
}

